      box-shadow: var(--shadow-md);
      transition: all 0.3s ease;

      &:hover {
        transform: translateY(-10px);
        box-shadow: var(--shadow-lg);
      }

      .training-icon {
        font-size: 50px;
        margin-bottom: 20px;
      }

      h3 {
        font-size: 20px;
        color: var(--dark-primary);
        margin-bottom: 20px;
      }

      ul {
        list-style: none;
        padding: 0;
        margin: 0;

        li {
          padding: 8px 0 8px 20px;
          font-size: 14px;
          color: var(--text-muted);
          position: relative;

          &::before {
            content: '✓';
            position: absolute;
            left: 0;
            color: var(--primary-blue);
            font-weight: 700;
          }
        }
      }
    }

    .training-schedule {
      background: var(--bg-section-light);
      padding: 50px;
      border-radius: 20px;

      h3 {
        text-align: center;
        font-size: 28px;
        color: var(--dark-primary);
        margin-bottom: 40px;
      }
    }

    .schedule-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 25px;
    }

    .schedule-item {
      background: white;
      padding: 25px;
      border-radius: 12px;
      text-align: center;
      box-shadow: var(--shadow-md);

      .schedule-month {
        font-size: 18px;
        font-weight: 700;
        color: var(--primary-blue-dark);
        margin-bottom: 10px;
      }

      .schedule-activity {
        font-size: 14px;
        color: var(--text-muted);
      }
    }

    /* RECRUITMENT CTA */
    .recruitment-cta {
      background: linear-gradient(135deg, var(--primary-blue) 0%, var(--primary-blue-dark) 100%);
      color: white;
    }

    .recruitment-content {
      text-align: center;
      max-width: 800px;
      margin: 0 auto;

      h2 {
        font-size: clamp(2rem, 4vw, 3rem);
        margin-bottom: 20px;
      }

      p {
        font-size: 1.1rem;
        line-height: 1.8;
        margin-bottom: 40px;
        opacity: 0.95;
      }
    }

    .recruitment-buttons {
      display: flex;
      justify-content: center;
      gap: 20px;
      flex-wrap: wrap;
    }

    /* CTA SECTION */
    .cta-section {
      background: var(--dark-primary);
      text-align: center;
      padding: 80px 0;

      h2 {
        color: white;
        font-size: clamp(2rem, 4vw, 3rem);
        margin-bottom: 15px;
      }

      p {
        color: rgba(255, 255, 255, 0.9);
        font-size: 1.2rem;
        margin-bottom: 30px;
      }
    }

    /* RESPONSIVE */
    @media (max-width: 1024px) {
      .leadership-grid {
        grid-template-columns: 1fr;
      }

      .leader-card {
        grid-template-columns: 1fr;
      }

      .leader-image-container {
        min-height: 400px;
      }

      .requirements-grid {
        grid-template-columns: 1fr;
      }

      .requirements-stats {
        position: static;
      }
    }

    @media (max-width: 768px) {
      .page-hero {
        padding: 120px 0 60px;
      }

      .stats-grid {
        grid-template-columns: repeat(2, 1fr);
      }

      .team-grid,
      .departments-grid,
      .training-grid {
        grid-template-columns: 1fr;
      }

      .leader-content {
        padding: 25px;
      }

      .recruitment-buttons {
        flex-direction: column;
        align-items: stretch;
      }
    }
  `]
})
